/** CmmtBoardArticleCnDao.insertList */
insert into cmmt_board_article_cn (
	 article_cn_id
	,article_id
	,sort_order
	,header
	,article_cn
) values

	(
		 #{item.articleCnId}
		,#{item.articleId}
		,#{item.sortOrder}
		,#{item.header}
		,#{item.articleCn}
	)

mapper.delete:
/** CmmtBoardArticleCnDao.deleteList */
delete from cmmt_board_article_cn
where
	article_id = #{articleId}
